out=[]
for dp,dn,fn in os.walk('.'):
    for f in fn:
        if not f.endswith('.go') or f.endswith('_test.go'): continue
        p=os.path.join(dp,f)
        lines=open(p,encoding='utf8',errors='ignore').read().split('\n')
        cur=None
        for i,l in enumerate(lines):
            s=l.strip()
            if cur is None:
                m=re.match(r'type\s+(\w+)\s+struct\s*\{\s*$',s)
                if m: cur=m.group(1)
                continue
            if s=='}': cur=None; continue
            if pat.search(s) and not s.startswith('//'):
                out.append(f"{p}:{i+1}: [{cur}] {s}")
for o in sorted(out): print(o)
EOF
